module top_module(
cnt      ,  
data     ,  
load     ,  
enable   ,  
clk      ,  
reset       
);output [7:0] cnt;

input [7:0] data;
input load, enable, clk, reset;

reg [7:0] cnt;

always @(posedge clk)
if (reset) begin
  cnt <= 8'b0 ;
end else if (load) begin
  cnt <= data;
end else if (enable) begin
  cnt <= cnt + 1;
end

endmodule
